# Regular class (boilerplate)
class Person:
    def __init__(self, name, age, city):
        self.name = name
        self.age = age
        self.city = city

    def __repr__(self):
        return f"Person(name='{self.name}', age={self.age}, city='{self.city}')"

    def __eq__(self, other):
        return (self.name, self.age, self.city) == (other.name, other.age, other.city)

# Data class (no boilerplate!)
@dataclass
class Person:
    name: str
    age: int
    city: str

from dataclasses import dataclass

@dataclass(frozen=True)
class Point:
    x: float
    y: float

p = Point(10, 20)
print(p)  # Output: Point(x=10.0, y=20.0)

# Cannot modify (frozen)
try:
    p.x = 30  # Raises error
except Exception as e:
    print(f"Error: {e}")  # Output: Error: cannot assign to field 'x'
